#include <bits/stdc++.h>
using namespace std;
struct coor{
	int x,y;
}c[151];
double dot_dist(coor a,coor b){
	return sqrt(1.0*(a.x-b.x)*(a.x-b.x)+1.0*(a.y-b.y)*(a.y-b.y));
}
int n,num[151];
double max_dist_num[151],g[151][151],f[151][151],max_dist[151],ans=1000000000;
void dfs(int number,int x){
    num[x]=number;
    for(int i=1;i<=n;i++)
        if(g[x][i] && !num[i])
            dfs(number,i);
}
int main(){
	memset(f,127,sizeof(f));
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>c[i].x>>c[i].y;
		f[i][i]=0;
	}
	for(int i=1;i<=n;i++){
		string s;
		cin>>s;
		s=" "+s;
		for(int j=1;j<=n;j++)
			if(s[j]=='1')
				g[i][j]=f[i][j]=dot_dist(c[i],c[j]);
	}
	int sum=0;
	for(int i=1;i<=n;i++)
	    if(!num[i])
	        dfs(++sum,i);
	for(int k=1;k<=n;k++)
		for(int i=1;i<=n;i++)
			for(int j=1;j<=n;j++)
				if(f[i][k]<(1<<30) && f[k][j]<(1<<30))
					f[i][j]=min(f[i][j],f[i][k]+f[k][j]);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			if(f[i][j]<(1<<30))
				if(f[i][j]>max_dist[i])
					max_dist[i]=f[i][j],max_dist_num[num[i]]=max(max_dist_num[num[i]],max_dist[i]);
	for(int i=1;i<=n;i++)
		for(int j=i+1;j<=n;j++)
			if(f[i][j]>=(1<<30))
				ans=min(ans,max(max_dist[i]+max_dist[j]+dot_dist(c[i],c[j]),max(max_dist_num[num[i]],max_dist_num[num[j]])));
	printf("%.6lf",ans);
	return 0;
}
